@inject IJSRuntime JS
@implements IAsyncDisposable

<div @ref="_dropZoneRef" class="file-drop-zone @(_isDragOver ? "drag-over" : "")">
    <p>Drag &amp; drop files here</p>
</div>

@if (_files.Count > 0)
{
    <ul class="file-list">
        @foreach (var entry in _files)
        {
            <li class="file-entry @(entry.Error is not null ? "file-error" : "")">
                @if (entry.Error is not null)
                {
                    <span class="file-error-message">@entry.Info.Name &mdash; @entry.Error</span>
                }
                else
                {
                    <span class="file-name">@entry.Info.Name</span>
                    <span class="file-size">@FormatSize(entry.Info.Size)</span>
                    <span class="file-type">@entry.Info.Type</span>
                }
                <button class="btn-remove" @onclick="() => Remove(entry)">Remove</button>
            </li>
        }
    </ul>
}

@code {
    private const long MaxFileSizeBytes = 10 * 1024 * 1024; // 10 MB

    private ElementReference _dropZoneRef;
    private IJSObjectReference? _module;
    private DotNetObjectReference<FileDropZone>? _dotNetRef;
    private bool _isDragOver;
    private readonly List<FileEntry> _files = new();

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/FileDropZone.razor.js");
            _dotNetRef = DotNetObjectReference.Create(this);
            await _module.InvokeVoidAsync("initDropZone", _dropZoneRef, _dotNetRef);
        }
    }

    [JSInvokable]
    public void OnDragOverChanged(bool isDragOver)
    {
        _isDragOver = isDragOver;
        InvokeAsync(StateHasChanged);
    }

    [JSInvokable]
    public async Task OnFilesDropped(FileDropData[] droppedFiles)
    {
        _isDragOver = false;

        foreach (var file in droppedFiles)
        {
            var info = new FileInfo(file.Name, file.Size, file.Type);
            string? error = file.Size > MaxFileSizeBytes
                ? $"File exceeds the 10 MB limit ({FormatSize(file.Size)})"
                : null;
            _files.Add(new FileEntry(info, error));
        }

        await NotifyParent();
        StateHasChanged();
    }

    private async Task Remove(FileEntry entry)
    {
        _files.Remove(entry);
        await NotifyParent();
    }

    private async Task NotifyParent()
    {
        var accepted = _files
            .Where(f => f.Error is null)
            .Select(f => f.Info)
            .ToList();
        await OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes) => bytes switch
    {
        < 1024 => $"{bytes} B",
        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
        _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
    };

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            await _module.InvokeVoidAsync("dispose", _dropZoneRef);
            await _module.DisposeAsync();
        }
        _dotNetRef?.Dispose();
    }

    private sealed record FileEntry(FileInfo Info, string? Error);
    private sealed record FileDropData(string Name, long Size, string Type);
}

